// Rainbow-pulse the on-board WS2812. Press BOOT to change speed.
// Everything runs live: just Connect (simulator or the real board).

fn on_start() {
    pin(28).input_pullup();          // BOOT button (GPIO28)
    this.hue = 0.0;
    this.speed = 1.0;
    log("rainbow running - press BOOT to change speed");
}

fn on_tick(dt_ms) {
    this.hue = (this.hue + dt_ms.to_float() * 0.06 * this.speed) % 360.0;
    let c = hsv(this.hue, 1.0, 0.35);
    rgb(c[0], c[1], c[2]);
}

fn on_pin(gpio, high) {
    if gpio == 28 && !high {         // pressed = pulled low
        this.speed = if this.speed >= 8.0 { 0.5 } else { this.speed * 2.0 };
        log(`speed x${this.speed}`);
    }
}

// Classic HSV -> RGB; returns [r, g, b] as 0..255 ints.
fn hsv(h, s, v) {
    let c = v * s;
    let x = c * (1.0 - ((h / 60.0) % 2.0 - 1.0).abs());
    let m = v - c;
    let f = if h < 60.0 { [c, x, 0.0] }
        else if h < 120.0 { [x, c, 0.0] }
        else if h < 180.0 { [0.0, c, x] }
        else if h < 240.0 { [0.0, x, c] }
        else if h < 300.0 { [x, 0.0, c] }
        else { [c, 0.0, x] };
    [((f[0] + m) * 255.0).to_int(),
     ((f[1] + m) * 255.0).to_int(),
     ((f[2] + m) * 255.0).to_int()]
}
